  "title": "ग्लोबल सेकेंडरी इंडेक्स",
  "group": "डायनेमोडीबी इंडेक्स",
  "options": [
    {
      "text": "प्राइमरी की के समान"
    },
    {
      "text": "अतिरिक्त लागत से मुक्त"
    },
    {
      "text": "राइट परफॉर्मेंस को कम करता है"
    },
    {
      "text": "नॉन-प्राइमरी एट्रिब्यूट्स पर क्वेरी करने की अनुमति देता है"
    }
  ],
  "questionProse": [
    "डायनेमोडीबी में ग्लोबल सेकेंडरी इंडेक्स का उद्देश्य क्या है?"
  ],
  "explanationProse": [
    "ग्लोबल सेकेंडरी इंडेक्स (GSI):\n  - नॉन-प्राइमरी की एट्रिब्यूट्स पर क्वेरी करने की अनुमति देता है\n  - वैकल्पिक एक्सेस पैटर्न बनाता है\n  - क्वेरी की लचीलापन बढ़ाता है\n  - अतिरिक्त राइट कैपेसिटी लागत के साथ आता है\n\n  प्राइमरी की से परे जटिल क्वेरी आवश्यकताओं के लिए उपयोगी।\n\n  [डायनेमोडीबी इंडेक्स](https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/GSI.html)"
  ]
}
